package main

import (
	"fmt"
	"sync"
	"time"
	"math/rand"
)

type Job struct {
	ID   int
	Data string
}

type Result struct {
	JobID  int
	Value  string
	Err    error
}

type WorkerPool struct {
	mu        sync.Mutex
	results   []Result
	maxRetry  int
	backoff   time.Duration
}

func NewWorkerPool(maxRetry int, backoff time.Duration) *WorkerPool {
	return &WorkerPool{
		maxRetry: maxRetry,
		backoff:  backoff,
	}
}

func (wp *WorkerPool) worker(id int, jobs <-chan Job, wg *sync.WaitGroup) {
	defer wg.Done()
	for job := range jobs {
		var result Result
		var err error
		for attempt := 0; attempt <= wp.maxRetry; attempt++ {
			result, err = processJob(job)
			if err == nil {
				break
			}
			time.Sleep(wp.backoff * time.Duration(attempt+1))
		}
		if err != nil {
			result = Result{JobID: job.ID, Err: fmt.Errorf("job %d failed after %d retries: %w", job.ID, wp.maxRetry, err)}
		}
		wp.mu.Lock()
		wp.results = append(wp.results, result)
		wp.mu.Unlock()
	}
}

func processJob(job Job) (Result, error) {
	if rand.Intn(10) < 2 {
		return Result{}, fmt.Errorf("transient error for job %d", job.ID)
	}
	return Result{JobID: job.ID, Value: fmt.Sprintf("processed-%s", job.Data)}, nil
}

func main() {
	wp := NewWorkerPool(3, 100*time.Millisecond)
	jobs := make(chan Job, 10)
	var wg sync.WaitGroup
	for i := 0; i < 3; i++ {
		wg.Add(1)
		go wp.worker(i, jobs, &wg)
	}
	for i := 0; i < 20; i++ {
		jobs <- Job{ID: i, Data: fmt.Sprintf("item-%d", i)}
	}
	close(jobs)
	wg.Wait()
	fmt.Printf("Results: %d\n", len(wp.results))
}

